};

const App: React.FC = () => {
  const [userContext, setUserContext] = useState<string | null>(null);
  const [allReports, setAllReports] = useState<Report[]>([]);
  const [filteredReports, setFilteredReports] = useState<Report[]>([]);
  const [reportsForStatusView, setReportsForStatusView] = useState<Report[]>([]);
  const [filters, setFilters] = useState({ lgu: 'All', type: 'All', status: 'All', frequency: 'All' });
  const [activeTab, setActiveTab] = useState("Monitoring Dashboard");
  const [activeSubTab, setActiveSubTab] = useState<string>(""); 
  const [dashboardView, setDashboardView] = useState<'matrix' | 'submission' | 'chart'>('submission');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isMaximized, setIsMaximized] = useState(false);
  const [editingReport, setEditingReport] = useState<Report | null>(null);
  const [showImportModal, setShowImportModal] = useState(false);
  const [showPendingModal, setShowPendingModal] = useState(false);
  const [barangayCityFilter, setBarangayCityFilter] = useState('All');
  const [barangayBarangayFilter, setBarangayBarangayFilter] = useState('All');
  const [confirmationStep, setConfirmationStep] = useState<0 | 1 | 2>(0);
  const [confirmationType, setConfirmationType] = useState<'reset' | 'batchZero' | 'batchBfdp' | 'batchSkfpd' | 'batchUpdateGeneric' | null>(null);
  const [batchParams, setBatchParams] = useState<{col: string, val: string} | null>(null);
  const [isBatchMode, setIsBatchMode] = useState(false);
  const [pendingBatchDetails, setPendingBatchDetails] = useState<any>(null);

  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [aiLoading, setAiLoading] = useState(false);

  const isEmbedded = useMemo(() => new URLSearchParams(window.location.search).get('embed') === 'true', []);

  const navItems = useMemo(() => {
    if (userContext === 'Province') return TAB_ORDER.filter(tab => tab !== "Action Logsheet" && tab !== "Compliance Checklist");
    return TAB_ORDER.filter(tab => tab !== "Capacity Development Activities" && tab !== "Barangay Reports Summary");
  }, [userContext]);

  const activeReportDef = useMemo(() => REPORT_DEFINITIONS.find(d => d.id === activeSubTab), [activeSubTab]);
  const currentDate = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const reports = await fetchReports();
      setAllReports(reports);
    } catch (err: any) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const handleUserSelection = (identity: string) => {
      setUserContext(identity);
      if (identity !== 'Province') {
          setFilters(prev => ({ ...prev, lgu: identity }));
          setBarangayCityFilter(identity);
          // Changed default tab to Monitoring Dashboard for LGU users
          setActiveTab("Monitoring Dashboard");
      }
  };

  useEffect(() => {
    let reports = allReports;
    if (activeSubTab && activeTab === "Monitoring Dashboard") {
        reports = reports.filter(r => r['REPORT TYPE'] === activeSubTab);
    }
    if (filters.lgu !== 'All') {
      reports = reports.filter(r => r['LGU/BARANGAY'] === filters.lgu || r['LGU/BARANGAY'].endsWith(`, ${filters.lgu}`));
    }
    setReportsForStatusView(reports);
    if (filters.status !== 'All') {
        reports = reports.filter(r => filters.status === 'Completed' ? r.STATUS === 'Completed' : (r.STATUS === 'Pending' || r.STATUS === 'Overdue' || r.STATUS === 'Partial'));
    }
    setFilteredReports(reports);
  }, [filters, allReports, activeTab, activeSubTab]);

  const currentViewLatestUpdate = useMemo(() => {
    if (filteredReports.length === 0) return '';
    let latest = '';
    filteredReports.forEach(r => {
        const dateStr = r['LAST UPDATED'];
        if (dateStr && dateStr !== 'Legacy Data' && (!latest || new Date(dateStr) > new Date(latest))) {
            latest = dateStr;
        }
    });
    return latest;
  }, [filteredReports]);

  const activeExtension = useMemo(() => {
      if (!activeReportDef?.extensionUntil) return null;
      const until = new Date(activeReportDef.extensionUntil);
      return new Date() <= until ? activeReportDef.extensionUntil : null;
  }, [activeReportDef]);

  const stats = useMemo(() => {
    const relevantDefs = REPORT_DEFINITIONS.filter(d => !d.isInventory);
    const total = relevantDefs.length;
    let compliant = 0;

    const sourceReports = filters.lgu === 'All' 
        ? allReports 
        : allReports.filter(r => r['LGU/BARANGAY'] === filters.lgu || r['LGU/BARANGAY'].endsWith(`, ${filters.lgu}`));

    relevantDefs.forEach(def => {
        const relevant = sourceReports.filter(r => r['REPORT TYPE'] === def.id);
        if (relevant.length > 0 && relevant.every(r => r.STATUS === 'Completed')) {
            compliant++;
        }
    });

    return { 
        totalReports: total, 
        completedReports: compliant, 
        pendingReports: total - compliant, 
        activeLgus: filters.lgu !== 'All' ? 1 : 26 
    };
  }, [allReports, filters.lgu]);

  const filterOptions = useMemo(() => ({ 
      lgus: ['All', ...LGU_LIST], 
      types: ['All', ...Array.from(new Set(REPORT_DEFINITIONS.filter(d => !d.isInventory).map(d => d.id))).sort()], 
      statuses: ['All', 'Completed', 'Pending', 'Partial'], 
      frequencies: ['All', ...Array.from(new Set(REPORT_DEFINITIONS.filter(d => !d.isInventory).map(d => d.category))).sort()] 
  }), []);

  const ftjsFilterOptions = useMemo(() => {
    const reports = allReports.filter(r => r['REPORT TYPE'] === activeSubTab);
    const cities = Array.from(new Set(reports.map(r => r.details?.city).filter(Boolean))).sort();
    const brgys = barangayCityFilter !== 'All' ? Array.from(new Set(reports.filter(r => r.details?.city === barangayCityFilter).map(r => r.details?.barangay).filter(Boolean))).sort() : [];
    return { cityOptions: ['All', ...cities], barangayOptions: ['All', ...brgys] };
  }, [allReports, activeSubTab, barangayCityFilter]);

  const displayedFtjsReports = useMemo(() => filteredReports.filter(r => (barangayCityFilter === 'All' || r.details?.city === barangayCityFilter) && (barangayBarangayFilter === 'All' || r.details?.barangay === barangayBarangayFilter)), [filteredReports, barangayCityFilter, barangayBarangayFilter]);

  const handleNavigateToReport = (def: ReportDefinition) => { 
    setActiveSubTab(def.id); 
    setActiveTab("Monitoring Dashboard");
    if (userContext && userContext !== 'Province') setBarangayCityFilter(userContext); 
  };

  const handleBackToDashboard = () => setActiveSubTab("");

  const pendingLguList = useMemo(() => {
      if (!activeSubTab || !activeReportDef) return [];
      const relevant = allReports.filter(r => r['REPORT TYPE'] === activeSubTab && r.STATUS !== 'Completed');
      return Array.from(new Set(relevant.map(r => r['LGU/BARANGAY'].includes(',') ? r['LGU/BARANGAY'].split(',')[1].trim() : r['LGU/BARANGAY']))).sort();
  }, [allReports, activeSubTab, activeReportDef]);

  const ftjsSummary = useMemo(() => LGU_LIST.map(city => {
      const reports = allReports.filter(r => r['REPORT TYPE'] === 'FTJS' && r.details?.city === city);
      const submitted = reports.filter(r => r.STATUS === 'Completed').length;
      return { city, totalBarangays: BARANGAY_COUNTS[city] || 0, beneficiaries: reports.reduce((s, r) => s + Number(r.details?.totalBeneficiaries || 0), 0), male: reports.reduce((s, r) => s + Number(r.details?.male || 0), 0), female: reports.reduce((s, r) => s + Number(r.details?.female || 0), 0), hs: reports.reduce((s, r) => s + Number(r.details?.hs || 0), 0), college: reports.reduce((s, r) => s + Number(r.details?.college || 0), 0), osy: reports.reduce((s, r) => s + Number(r.details?.osy || 0), 0), complianceRate: Math.round((submitted / (BARANGAY_COUNTS[city] || 1)) * 100) };
  }), [allReports]);

  const ftjsTotals = useMemo(() => ftjsSummary.reduce((acc, curr) => ({ totalBarangays: acc.totalBarangays + curr.totalBarangays, beneficiaries: acc.beneficiaries + curr.beneficiaries, male: acc.male + curr.male, female: acc.female + curr.female, hs: acc.hs + curr.hs, college: acc.college + curr.college, osy: acc.osy + curr.osy }), { totalBarangays: 0, beneficiaries: 0, male: 0, female: 0, hs: 0, college: 0, osy: 0 }), [ftjsSummary]);

  const asfSummary = useMemo(() => LGU_LIST.map(city => {
      const reports = allReports.filter(r => r['REPORT TYPE'] === 'ASF (Barangay)' && r.details?.city === city);
      return { city, totalBarangays: BARANGAY_COUNTS[city] || 0, compliantBarangays: reports.filter(r => r.STATUS === 'Completed').length, checkpoints: reports.filter(r => r.details?.checkpoints === '/').length, meatMonitoring: reports.filter(r => r.details?.meatMonitoring === '/').length, piggeryMonitoring: reports.filter(r => r.details?.piggeryMonitoring === '/').length, awareness: reports.filter(r => r.details?.awareness === '/').length, dti: reports.filter(r => r.details?.dtiCoordination === '/').length, swillBan: reports.filter(r => r.details?.swillFeedBan === '/').length, pnp: reports.filter(r => r.details?.pnpSupport === '/').length };
  }), [allReports]);

  const asfTotals = useMemo(() => asfSummary.reduce((acc, curr) => ({ totalBarangays: acc.totalBarangays + curr.totalBarangays, compliantBarangays: acc.compliantBarangays + curr.compliantBarangays, checkpoints: acc.checkpoints + curr.checkpoints, meatMonitoring: acc.meatMonitoring + curr.meatMonitoring, piggeryMonitoring: acc.piggeryMonitoring + curr.piggeryMonitoring, awareness: acc.awareness + curr.awareness, dti: acc.dti + curr.dti, swillBan: acc.swillBan + curr.swillBan, pnp: acc.pnp + curr.pnp }), { totalBarangays: 0, compliantBarangays: 0, checkpoints: 0, meatMonitoring: 0, piggeryMonitoring: 0, awareness: 0, dti: 0, swillBan: 0, pnp: 0 }), [asfSummary]);

  const vawVacSummary = useMemo(() => LGU_LIST.map(city => {
      const reports = allReports.filter(r => r['REPORT TYPE'] === 'VAW-VAC Incidents' && r.details?.city === city);
      return { city, totalVictims: reports.reduce((s, r) => s + Number(r.details?.totalVictims || 0), 0), physical: reports.reduce((s, r) => s + Number(r.details?.physicalAbuse || 0), 0), sexual: reports.reduce((s, r) => s + Number(r.details?.sexualAbuse || 0), 0), psych: reports.reduce((s, r) => s + Number(r.details?.psychAbuse || 0), 0), economic: reports.reduce((s, r) => s + Number(r.details?.economicAbuse || 0), 0), bpo: reports.reduce((s, r) => s + Number(r.details?.issuedBpo || 0), 0), lswdo: reports.reduce((s, r) => s + Number(r.details?.referredLswdo || 0), 0), pnp: reports.reduce((s, r) => s + Number(r.details?.referredPnp || 0), 0), nbi: reports.reduce((s, r) => s + Number(r.details?.referredNbi || 0), 0), medical: reports.reduce((s, r) => s + Number(r.details?.referredMedical || 0), 0), legal: reports.reduce((s, r) => s + Number(r.details?.referredLegal || 0), 0), court: reports.reduce((s, r) => s + Number(r.details?.referredCourt || 0), 0), others: reports.reduce((s, r) => s + Number(r.details?.others || 0), 0) };
  }), [allReports]);

  const vawVacTotals = useMemo(() => vawVacSummary.reduce((acc, curr) => ({ totalVictims: acc.totalVictims + curr.totalVictims, physical: acc.physical + curr.physical, sexual: acc.sexual + curr.sexual, psych: acc.psych + curr.psych, economic: acc.economic + curr.economic, bpo: acc.bpo + curr.bpo, lswdo: acc.lswdo + curr.lswdo, pnp: acc.pnp + curr.pnp, nbi: acc.nbi + curr.nbi, medical: acc.medical + curr.medical, legal: acc.legal + curr.legal, court: acc.court + curr.court, others: acc.others + curr.others }), { totalVictims: 0, physical: 0, sexual: 0, psych: 0, economic: 0, bpo: 0, lswdo: 0, pnp: 0, nbi: 0, medical: 0, legal: 0, court: 0, others: 0 }), [vawVacSummary]);

  const barcoSummary = useMemo(() => LGU_LIST.map(city => {
      const reports = allReports.filter(r => r['REPORT TYPE'] === 'BARCO' && r.details?.city === city);
      const total = BARANGAY_COUNTS[city] || 0;
      const conducted = reports.filter(r => r.STATUS === 'Completed' && r.details?.conducted === '1').length;
      return { city, totalBarangays: total, conductedCount: conducted, complianceRate: Math.round((conducted / (total || 1)) * 100) };
  }), [allReports]);

  const barcoTotals = useMemo(() => barcoSummary.reduce((acc, curr) => ({ totalBarangays: acc.totalBarangays + curr.totalBarangays, conductedCount: acc.conductedCount + curr.conductedCount }), { totalBarangays: 0, conductedCount: 0 }), [barcoSummary]);

  const lguMatrixData = useMemo(() => LGU_LIST.map(lgu => {
      const rowData: any = { lgu };
      let compCount = 0;
      const matrixDefs = REPORT_DEFINITIONS.filter(d => !d.isInventory);
      matrixDefs.forEach(def => {
          const isBrgyReport = BARANGAY_LEVEL_REPORT_IDS.includes(def.id);
          const lguReports = allReports.filter(r => (r['LGU/BARANGAY'] === lgu || r.details?.city === lgu) && r['REPORT TYPE'] === def.id);

          let overallStatus = 'Pending';
          let displayDate = 'Pending';

          if (lguReports.length > 0) {
              const allCompleted = lguReports.every(r => r.STATUS === 'Completed');
              const somePartial = lguReports.some(r => r.STATUS === 'Partial' || r.STATUS === 'Completed');

              if (allCompleted) {
                  overallStatus = 'Completed';
                  compCount++;
              } else if (somePartial) {
                  overallStatus = 'Partial';
              }

              const dates = lguReports.map(r => r['LAST UPDATED']).filter(d => d && d !== 'Pending' && d !== 'Data Present');
              if (dates.length > 0) {
                  displayDate = dates.sort((a, b) => new Date(b).getTime() - new Date(a).getTime())[0];
              } else if (somePartial) {
                  displayDate = 'Data Present';
              }
          }

          rowData[def.id] = { status: overallStatus, date: displayDate };
      });
      rowData.completionRate = Math.round((compCount / matrixDefs.length) * 100);
      rowData.completedCount = compCount; 
      rowData.pendingCount = matrixDefs.length - compCount;
      return rowData;
  }), [allReports]);

  const handleSaveReport = async (updatedDetails: any) => {
    if (!editingReport) return;
    if (isBatchMode) { 
        setPendingBatchDetails(updatedDetails); 
        setEditingReport(null); 
        setConfirmationType('batchUpdateGeneric'); 
        setConfirmationStep(1); 
        return; 
    }
    setLoading(true);
    try {
        const idKey = updatedDetails.project || editingReport['LGU/BARANGAY'];
        await updateReportData(editingReport['REPORT TYPE'], idKey, updatedDetails);
        await loadData();
        setEditingReport(null);
    } catch (err: any) { 
        alert("Save failed: " + (err instanceof Error ? err.message : String(err))); 
    } finally { 
        setLoading(false); 
    }
  };

  const handleModalConfirmation = async () => {
      setConfirmationStep(0); 
      setLoading(true);
      try {
          if (confirmationType === 'batchBfdp' && batchParams) await batchUpdateBfdpColumn(barangayCityFilter, batchParams.col, batchParams.val);
          if (confirmationType === 'batchUpdateGeneric' && pendingBatchDetails) await batchUpdateBarangayReport(activeSubTab, barangayCityFilter, pendingBatchDetails);
          await loadData();
      } catch (e: any) { 
          alert("Batch update failed."); 
      } finally { 
          setLoading(false); 
          setIsBatchMode(false); 
          setConfirmationType(null); 
      }
  };

  const generateAiInsights = async () => {
    setAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
      const context = lguMatrixData.slice(0, 10).map(l => `${l.lgu}: ${l.completionRate}%`).join(', ');
      const response = await ai.models.generateContent({ 
        model: 'gemini-3-flash-preview', 
        contents: `Analyze these compliance rates for LGUs in Samar: ${context}. Identify top performers and those needing assistance. Provide a succinct 3-sentence summary for the provincial director.` 
      });
      setAiInsights(response.text || "Insights unavailable.");
    } catch (err: any) { 
        setAiInsights("AI Analysis service is currently offline. Please try again later."); 
    } finally { 
        setAiLoading(false); 
    }
  };

  const handleDownloadPdfSummary = () => {
      if (!(window as any).jspdf) return;
      const { jsPDF } = (window as any).jspdf;
      const doc = new jsPDF('l', 'mm', 'a4');
      const dateStr = new Date().toLocaleDateString();
      let title = "Barangay Summary";
      let headers: string[] = [];
      let data: any[] = [];
      let keys: string[] = [];
      let summaryTotal: any = null;
      if (activeSubTab === 'FTJS Summary') {
          title = "FTJS Summary";
          headers = ['LGU', 'Total Brgys', 'Beneficiaries', 'Male', 'Female', 'HS/Elem', 'College', 'OSY', 'Compliance'];
          keys = ['totalBarangays', 'beneficiaries', 'male', 'female', 'hs', 'college', 'osy'];
          data = ftjsSummary.map(r => [r.city, r.totalBarangays, r.beneficiaries, r.male, r.female, r.hs, r.college, r.osy, `${r.complianceRate}%`]);
          summaryTotal = ftjsTotals;
      } else if (activeSubTab === 'ASF Summary') {
          title = "ASF Summary";
          headers = ['LGU', 'Total Brgys', 'Comp.', 'Checks', 'Meat Mon', 'Pig Mon', 'Aware', 'DTI', 'Swill', 'PNP'];
          keys = ['totalBarangays', 'compliantBarangays', 'checkpoints', 'meatMonitoring', 'piggeryMonitoring', 'awareness', 'dti', 'swillBan', 'pnp'];
          data = asfSummary.map(r => [r.city, r.totalBarangays, r.compliantBarangays, r.checkpoints, r.meatMonitoring, r.piggeryMonitoring, r.awareness, r.dti, r.swillBan, r.pnp]);
          summaryTotal = asfTotals;
      } else if (activeSubTab === 'VAW-VAC Summary') {
          title = "VAW-VAC Summary";
          headers = ['LGU', 'Victims', 'Phys', 'Sex', 'Psych', 'Econ', 'BPO', 'LSWDO', 'PNP', 'NBI', 'Med', 'Legal', 'Court', 'Other'];
          keys = ['totalVictims', 'physical', 'sexual', 'psych', 'economic', 'bpo', 'lswdo', 'pnp', 'nbi', 'medical', 'legal', 'court', 'others'];
          data = vawVacSummary.map(r => [r.city, r.totalVictims, r.physical, r.sexual, r.psych, r.economic, r.bpo, r.lswdo, r.pnp, r.nbi, r.medical, r.legal, r.court, r.others]);
          summaryTotal = vawVacTotals;
      } else if (activeSubTab === 'BARCO Summary') {
          title = "BARCO Summary";
          headers = ['LGU', 'Total Barangays', 'BaRCO Conducted', 'Compliance %'];
          keys = ['totalBarangays', 'conductedCount'];
          data = barcoSummary.map(r => [r.city, r.totalBarangays, r.conductedCount, `${r.complianceRate}%`]);
          summaryTotal = barcoTotals;
      }
      if (summaryTotal) data.push(["GRAND TOTAL", ...keys.map(k => summaryTotal[k]), "-"]);
