      </div>
      {editingReport && <EditReportModal report={editingReport} onSave={handleSaveReport} onClose={() => { setEditingReport(null); setIsBatchMode(false); }} />}
      {showImportModal && activeSubTab && <BatchImportModal definition={REPORT_DEFINITIONS.find(d => d.id === activeSubTab)!} onClose={() => setShowImportModal(false)} onImport={async (data) => { setLoading(true); try { const result = await importBatchData(String(activeSubTab), data); alert(result); loadData(); } catch (e: any) { alert("Import Failed"); } finally { setLoading(false); } }} />}
      {showPendingModal && (<div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-fade-in"><div className="bg-white rounded-2xl shadow-2xl w-full max-w-md max-h-[80vh] flex flex-col overflow-hidden border"><div className="px-6 py-5 border-b flex justify-between items-center bg-slate-50/50"><h3 className="font-bold text-slate-800 text-lg">Pending List</h3><button onClick={() => setShowPendingModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button></div><div className="p-0 overflow-y-auto flex-1 bg-white">{pendingLguList.length > 0 ? (<ul className="divide-y divide-slate-50">{pendingLguList.map((item, i) => (<li key={i} className="px-6 py-3 text-sm text-slate-600 font-medium hover:bg-slate-50 flex items-center transition-colors"><span className="w-2 h-2 rounded-full bg-amber-500 mr-3 shrink-0"></span>{item}</li>))}</ul>) : (<div className="p-12 text-center text-emerald-700 font-bold text-lg"><CheckIcon /> All LGUs are compliant!</div>)}</div><div className="px-6 py-4 border-t bg-slate-50/80 text-right"><button onClick={() => setShowPendingModal(false)} className="px-5 py-2 bg-slate-800 text-white text-sm font-bold rounded-xl">Close</button></div></div></div>)}
      {confirmationStep > 0 && (<div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm"><div className="bg-white rounded-2xl shadow-2xl w-full max-w-md mx-4 overflow-hidden border p-8">{confirmationStep === 1 ? (<><div className="flex items-center mb-5 text-amber-500"><div className="bg-amber-50 p-3 rounded-xl mr-4 shadow-sm"><svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg></div><h3 className="text-xl font-bold text-slate-800">Action Required</h3></div><p className="text-slate-600 mb-8 leading-relaxed text-sm">You are about to execute a batch operation on <strong className="text-slate-900">{barangayCityFilter}</strong>. This will modify multiple records.</p><div className="flex justify-end space-x-3"><button onClick={() => { setConfirmationStep(0); setConfirmationType(null); }} className="px-5 py-2.5 border border-slate-200 rounded-xl text-slate-600 font-bold text-sm hover:bg-slate-50">Cancel</button><button onClick={() => setConfirmationStep(2)} className="px-5 py-2.5 bg-amber-500 text-white rounded-xl font-bold text-sm hover:bg-amber-600">Continue</button></div></>) : (<><div className="flex items-center mb-5 text-red-600"><div className="bg-red-50 p-3 rounded-xl mr-4 shadow-sm"><svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></div><h3 className="text-xl font-bold text-slate-900">Final Confirmation</h3></div><p className="text-slate-600 mb-8 font-medium text-sm">Are you absolutely sure? This action <span className="text-red-600 font-bold bg-red-50 px-1 rounded">CANNOT BE UNDONE</span>.</p><div className="flex justify-end space-x-3"><button onClick={() => { setConfirmationStep(0); setConfirmationType(null); }} className="px-5 py-2.5 border border-slate-200 rounded-xl text-slate-600 font-bold text-sm hover:bg-slate-50">Cancel</button><button onClick={handleModalConfirmation} className="px-5 py-2.5 bg-red-600 text-white rounded-xl font-bold text-sm hover:bg-red-700">Yes, Execute</button></div></>)}</div></div>)}
    </div>
  );
};

export default App;
